parameters.functionCode:
// Parse extraction metrics from LangSmith traces
const runs = $json.data || [];
const metrics = {
  total_extractions: runs.length,
  successful_extractions: 0,
  failed_extractions: 0,
  avg_confidence: 0,
  avg_f1_score: 0,
  errors: [],
  low_confidence_cases: []
};

let total_confidence = 0;
let total_f1 = 0;
let f1_count = 0;

runs.forEach(run => {
  const output = run.outputs || {};
  const outputs_metrics = output.metrics || {};

  // Check for errors
  if (run.error) {
    metrics.failed_extractions++;
    metrics.errors.push({
      run_id: run.id,
      error: run.error,
      timestamp: run.created_at
    });
  } else {
    metrics.successful_extractions++;
  }

  // Track confidence
  if (outputs_metrics.avg_confidence) {
    total_confidence += outputs_metrics.avg_confidence;
    if (outputs_metrics.avg_confidence < 0.85) {
      metrics.low_confidence_cases.push({
        run_id: run.id,
        confidence: outputs_metrics.avg_confidence
      });
    }
  }

  // Track F1 score (from custom evaluators)
  if (outputs_metrics.f1_score) {
    total_f1 += outputs_metrics.f1_score;
    f1_count++;
  }
});

// Calculate averages
metrics.avg_confidence = total_confidence / runs.length || 0;
metrics.avg_f1_score = f1_count > 0 ? total_f1 / f1_count : 0;
metrics.error_rate = (metrics.failed_extractions / runs.length * 100) || 0;
metrics.low_confidence_rate = (metrics.low_confidence_cases.length / runs.length * 100) || 0;

return { extraction_metrics: metrics };

